#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,q,f[N][21],dep[N];
vector<int> g[N];

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    for(int y:g[x])
        if(y!=fa){
            f[y][0]=x;
            for(int j=1;f[f[y][j-1]][j-1];j++)
                f[y][j]=f[f[y][j-1]][j-1];
            dfs(y,x);
        }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=20;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=20;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

int main(){
    scanf("%d%d",&n,&q);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1,0);
    while(q--){
        int a,b,c,d;
        scanf("%d%d%d%d",&a,&b,&c,&d);
        int l1=LCA(a,b),l2=LCA(c,d);
        if(dep[LCA(a,c)]>=max(dep[l1],dep[l2]))
            puts("Y");
        else if(dep[LCA(a,d)]>=max(dep[l1],dep[l2]))
            puts("Y");
        else if(dep[LCA(b,c)]>=max(dep[l1],dep[l2]))
            puts("Y");
        else if(dep[LCA(b,d)]>=max(dep[l1],dep[l2]))
            puts("Y");
        else
            puts("N");
    }
    return 0;
}
